const chatId = $('Update state: create_lead__enter_source').first().json.id

const dataJson = $("Get sources").all().map(item => item.json);

const inline_keyboard = dataJson.map(item => [
  { text: item.title, callback_data: `lead_source__${item.title}` }
]);


return [
  {
    json: {
      chat_id: chatId,
      text: "Выберите источник лида 👇",
      reply_markup: {
        inline_keyboard
      }
    }
  }
];

const obj = $('Switch: manager callback').first().json;

const stateData = JSON.parse(obj.state_data);

stateData.create_lead.source = $('Telegram Trigger').first().json.callback_query.data.replace("lead_source__", "");

obj.state_data = JSON.stringify(stateData);

return [
  {
    json: obj
  }
];
